<span class="line"><span style="color:#CDD6F4;">                _ </span><span style="color:#94E2D5;">=&gt;</span><span style="color:#F9E2AF;font-style:italic;"> StopReason</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">EndTurn</span><span style="color:#9399B2;">,</span></span>
